external_knowledge:
- 'peak of their operation' refers to components that are active;
- 'guiding principles' are represented by preference keys;
- 'core team' indicates default roles (is_default = 1);
- 'approved manual' means documentation that is approved (is_approved = 1).

sql:
SELECT components.component_name, preferences.preference_key, preferences.preference_value
FROM components
INNER JOIN preferences ON components.component_id = preferences.component_id;

SELECT preference_id, data_type
FROM preferences
WHERE preference_key = 'getValues4';

SELECT c.component_name, m.method_name
FROM components c
LEFT JOIN methods m ON c.component_id = m.component_id;

SELECT p.*
FROM preferences p
WHERE p.preference_id NOT IN (
    SELECT al.preference_id
    FROM access_logs al
);

